header('Content-Type: text/html; charset=utf-8');
echo '<!DOCTYPE html><html><head><meta charset="utf-8"><title>Security Patch</title>
<style>
body{font-family:monospace;background:#1a1a2e;color:#e5e7eb;padding:30px}
h2{color:#f59e0b}
