<h2>&#128274; iBook &mdash; Security Patch</h2><pre>';

$root = is_dir(__DIR__ . '/../app') ? __DIR__ . '/..' : __DIR__;
$root = rtrim(realpath($root), '/\\');
echo "<span class='info'>[INFO]</span> App root: $root\n\n";

$ok = 0; $fail = 0;

function deployFile($root, $rel, $b64) {
    $full = $root . '/' . ltrim($rel, '/');
    $dir  = dirname($full);
    if (!is_dir($dir)) @mkdir($dir, 0755, true);
    $content = base64_decode($b64);
    if ($content === false) { echo "<span class='fail'>[GAGAL]</span> base64_decode: $rel\n"; return false; }
    @chmod($full, 0644);
    $w = @file_put_contents($full, $content);
    if ($w === false) { echo "<span class='fail'>[GAGAL TULIS]</span> $rel\n"; return false; }
    echo "<span class='ok'>[OK " . number_format($w) . " bait]</span> $rel\n";
    return true;
}

echo "<span class='sec'>── FAIL 1: AuthController.php ──</span>\n";
$f1 = '';
if (deployFile($root, 'app/Http/Controllers/Auth/AuthController.php', $f1)) $ok++; else $fail++;
echo "\n";

echo "<span class='sec'>── FAIL 2: AuditLogController.php ──</span>\n";
$f2 = '';
if (deployFile($root, 'app/Http/Controllers/AuditLogController.php', $f2)) $ok++; else $fail++;
echo "\n";

