echo "<span class='sec'>── FAIL 6: audit/index.blade.php ──</span>\n";
$f6 = '';
if (deployFile($root, 'resources/views/audit/index.blade.php', $f6)) $ok++; else $fail++;
echo "\n";

echo "<span class='sec'>── FAIL 7: Kosongkan blade cache ──</span>\n";
$cacheDir = $root . '/storage/framework/views';
$cl = 0;
if (is_dir($cacheDir)) {
    foreach (glob($cacheDir . '/*.php') as $f) {
        if (@unlink($f)) $cl++;
    }
}
