echo ($fail > 0 ? "<span class='fail'>Gagal: $fail</span>" : "<span class='ok'>Gagal: 0</span>");
echo "\n\n";

if ($fail === 0) {
    echo "<span class='ok'>&#10003; Security patch selesai. Semak /log-audit untuk log masuk baharu.</span>\n";
